var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하아. 벌써 우리 둘만 남았네. 원본부터 조잡한 잡종들이라 어쩔 수 없나.","JPN":"あーあ、私たち2人だけしか残らなかったわね。そもそもオリジナルが粗末な雑種だから仕方ないか。","ENG":"Oh dear… It's just us two already? I guess these mutts never had a chance, coming from such lousy originals.","TWN":"哈，只剩我們兩個嗎？沒辦法，誰叫那群本來就是烏合之眾呢？"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 오히려 좋아. 이런 고조감 정말 오랜만이거든.","JPN":"でもこっちのほうがいい。こんな高調感は本当に久しぶり。","ENG":"But I actually prefer this development. It's been ages since I've felt this level of crescendo.","TWN":"不過這樣也好，好久沒有這麼興奮的感覺。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너는 어때, 호라이즌? 우리 둘이 자아내는 선율이 정말 짜릿하지 않니?","JPN":"ホライズン、あなたはどう？　私たち二人で奏でる旋律が実に刺激的だと思わない？","ENG":"How about you, Horizon? Isn't our dissonant harmony simply tantalizing?","TWN":"你呢，地平線？不覺得我們兩個譜出的旋律很激昂嗎？"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"뇌하수체가 상한 것 아닙니까. 병원에나 가 보십시오.","JPN":"脳下垂体の異常が考えられます。病院に行って受診してみてください。","ENG":"Such oxymoronic use of vocabulary may be a sign of a brain injury. I highly recommend you visit the nearest hospital.","TWN":"你的腦下垂體是不是有受損？要去看醫生嗎？"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"금속성 소음을 듣고 선율 운운하는 시점에서 판단력에 하자가 있다고 보입니다만.","JPN":"金属性の騒音を聴いて旋律云々と言う時点で判断力に欠陥があると思われますが。","ENG":"Besides, there's hardly anything harmonic about the noisy clashing of metal.","TWN":"雖然當你把那些金屬噪音當成旋律時，就表示你的判斷力已經出現瑕疵。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 틱틱거리는 것도 귀엽네. 내 동료들이 딱 너만큼만 앙칼졌어도 좋을 텐데.","JPN":"フフッ、つんつんしているのも可愛すぎるわ。私の仲間たちもあなたみたいに刺々しい感じだとよかったのに。","ENG":"Heh. I sure do love a good banter. I wish my colleagues were as feisty as you.","TWN":"呵呵～嘀嘀咕咕的樣子也很可愛呢～真希望我的同事們也跟你一樣毒舌～"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"동료 분들과 사이가 원만하지 않은 모양이군요. 그 성격으로 어련하겠습니까만.","JPN":"同僚の方との仲が円満ではないようですね。その性格だと仕方がありませんが。","ENG":"I take it that you do not get along with your colleagues. Hardly surprising, given your personality.","TWN":"你和同事的關係似乎不太好，不過以你的個性是完全可以理解的。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"왜, 내 성격이 어때서?","JPN":"えー私の性格がなんだっていうのよ。","ENG":"What's wrong with my personality?","TWN":"為什麼？我的個性怎樣？"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신이 제 사무실을 습격한 휴먼들을 살해할 때의 눈빛. 기록에 남아 있습니다.","JPN":"あなたが私の事務所を襲撃したヒューマンたちを殺害した時の目つき。記録に残っています。","ENG":"The frenzied look in your eyes when you murdered the humans who raided my office… There remains a record of it in my log files.","TWN":"你殺害那些入侵我的辦公室的人類時，當時的那個眼神都有記錄下來。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"응. 열정적이었지. 빗속에서 연주할 때는 나도 모르게 타오르거든.","JPN":"まあね。あの時はかなり情熱的だったわ。雨の中で演奏する時は、思わず熱くなってしまうから。","ENG":"Yeah. I sure got passionate back then. I tend to start playing molto appassionato when it's raining.","TWN":"嗯，眼神很炙熱吧？在雨中演奏時，我都會不自主地興奮起來。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들이 징그러운 벌레 보는 시선이더군요.","JPN":"ヒューマンたちを見るその目は、気持ち悪い虫を見る時の視線でした。","ENG":"I noticed you gazed upon the humans as they would a foul pest.","TWN":"那是人類看到噁心蟲子的眼神。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……호오.","JPN":"……へえ？","ENG":"Ooh…","TWN":"……喔。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"증오가 아닌 단순한 혐오. 주거지에 침입한 해충을 밟아 죽일 기회만 노리는 시선.","JPN":"憎悪ではなく単なる嫌悪。住居に侵入した害虫を踏み潰すチャンスだけを狙う視線。","ENG":"It was not so much hatred as it was simple disgust. You had that revolting look in your eyes before stomping on a cockroach that violated your home.","TWN":"不是憎恨，而是單純的嫌惡。眼神就像是，要抓住機會踩死那些入侵住家的害蟲一樣。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"리플레이서 융합체들을 처리했지만 침식파 반응은 사라지지 않았습니다.","JPN":"リプレイサー融合体たちを処理しましたが、侵食波反応は消えていません。","ENG":"The Replacer Hybriders have been neutralized, and yet the Corruption Ray signature remains.","TWN":"雖然已經處理掉克隆集團融合體，侵蝕波反應卻沒有消失。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 파형 분석 결과, 현재 이 상공에 유출된 침식파의 근원지는 당신입니다.","JPN":"そして波形分析の結果、現在この上空に流出している侵食波の源はあなたです。","ENG":"Analysis suggests that you are the source of the Corruption Ray radiation in this area.","TWN":"而且波形分析結果，現在流露至上空的侵蝕坡源頭就是你。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"가만히 이면세계에 있을 것이지, 왜 현실세계로 기어나왔습니까. 침식체.","JPN":"大人しく裏世界にいればいいのに、なぜ現実世界に出てきたのですか、侵食体。","ENG":"Why did you have to crawl out to the Normalside instead of staying put in the Counterside? You Corrupted Object.","TWN":"怎麼不乖乖待在異界，為什麼要爬到現世來呢，侵蝕體？"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"윽……?!","JPN":"うっ……！？","ENG":"Ugh…?!","TWN":"唔……？！"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};